import{_ as e,C as r,o as d,c as n,ag as o,E as i,w as l,a as s}from"./chunks/framework.BZohXCq9.js";const f=JSON.parse('{"title":"Catálogo de productos","description":"Administra los productos de tu tienda digital con fotos, precios, variantes y badges","frontmatter":{"title":"Catálogo de productos","description":"Administra los productos de tu tienda digital con fotos, precios, variantes y badges"},"headers":[],"relativePath":"cat/catalogo-productos.md","filePath":"cat/catalogo-productos.md"}'),c={name:"cat/catalogo-productos.md"};function u(p,t,h,g,m,b){const a=r("Note");return d(),n("div",null,[t[1]||(t[1]=o('<h2 id="¿que-es" tabindex="-1">¿Qué es? <a class="header-anchor" href="#¿que-es" aria-label="Permalink to &quot;¿Qué es?&quot;">​</a></h2><p>El catálogo de productos es la sección central de SYNTIcat. Desde tu panel administras todos tus productos: fotos, precios, variantes (talla, color), badges y disponibilidad. En la landing, tus clientes ven un catálogo visual profesional con tarjetas de producto.</p><h2 id="¿donde-lo-encuentro" tabindex="-1">¿Dónde lo encuentro? <a class="header-anchor" href="#¿donde-lo-encuentro" aria-label="Permalink to &quot;¿Dónde lo encuentro?&quot;">​</a></h2><p><strong>Tu panel → Qué Vendes</strong> (segundo ícono en el menú lateral, 🛒)</p><h2 id="¿que-hace" tabindex="-1">¿Qué hace? <a class="header-anchor" href="#¿que-hace" aria-label="Permalink to &quot;¿Qué hace?&quot;">​</a></h2><h3 id="crear-editar-un-producto" tabindex="-1">Crear / editar un producto <a class="header-anchor" href="#crear-editar-un-producto" aria-label="Permalink to &quot;Crear / editar un producto&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Campo</th><th>Obligatorio</th><th>Descripción</th></tr></thead><tbody><tr><td><strong>Nombre</strong></td><td>✅ Sí</td><td>Nombre del producto</td></tr><tr><td><strong>Precio</strong></td><td>✅ Sí</td><td>Precio en REF</td></tr><tr><td><strong>Descripción</strong></td><td>No</td><td>Descripción detallada del producto</td></tr><tr><td><strong>Imágenes</strong></td><td>No</td><td>1 a 6 fotos según plan (máx 2MB, auto WebP 800px)</td></tr><tr><td><strong>Badge</strong></td><td>No</td><td>🆕 Nuevo, 🔥 Hot, 💰 Promo</td></tr><tr><td><strong>Activo</strong></td><td>—</td><td>Toggle para mostrar/ocultar en el catálogo</td></tr><tr><td><strong>Variantes</strong></td><td>No</td><td>Talla, color, talla+color u opciones libres (según plan)</td></tr></tbody></table><h3 id="variantes-de-producto" tabindex="-1">Variantes de producto <a class="header-anchor" href="#variantes-de-producto" aria-label="Permalink to &quot;Variantes de producto&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tipo de variante</th><th>Descripción</th><th>Plan mínimo</th></tr></thead><tbody><tr><td><strong>Simple</strong> (sin variantes)</td><td>Producto sin opciones</td><td>Básico</td></tr><tr><td><strong>Talla</strong> (<code>size</code>)</td><td>Selector de talla: XS, S, M, L, XL, etc.</td><td>Semestral</td></tr><tr><td><strong>Talla + Color</strong> (<code>size_color</code>)</td><td>Selector de talla y color combinados</td><td>Semestral</td></tr><tr><td><strong>Opciones libres</strong> (<code>options</code>)</td><td>Lista personalizable: extras, personalización, mensaje</td><td>Anual</td></tr></tbody></table><h3 id="badges-de-producto" tabindex="-1">Badges de producto <a class="header-anchor" href="#badges-de-producto" aria-label="Permalink to &quot;Badges de producto&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Badge</th><th>Ícono</th><th>Cuándo usarlo</th></tr></thead><tbody><tr><td><strong>Nuevo</strong></td><td>🆕</td><td>Producto recién llegado</td></tr><tr><td><strong>Hot</strong></td><td>🔥</td><td>Producto más vendido o tendencia</td></tr><tr><td><strong>Promo</strong></td><td>💰</td><td>Producto en oferta o promoción</td></tr></tbody></table><h3 id="en-la-landing-lo-que-ve-tu-cliente" tabindex="-1">En la landing (lo que ve tu cliente) <a class="header-anchor" href="#en-la-landing-lo-que-ve-tu-cliente" aria-label="Permalink to &quot;En la landing (lo que ve tu cliente)&quot;">​</a></h3><p>Los productos se muestran en un grid de tarjetas. Cada tarjeta muestra:</p><ul><li>Foto principal (con badge si tiene)</li><li>Nombre del producto</li><li>Precio (en REF/Bs según configuración de moneda)</li><li>Botón &quot;Agregar al carrito&quot; (Semestral+) o &quot;Consultar por WhatsApp&quot; (Básico)</li></ul><p>Si un producto está agotado, desactívalo con el toggle — desaparece del catálogo pero queda guardado para cuando vuelva a estar disponible.</p><h2 id="¿que-no-hace" tabindex="-1">¿Qué NO hace? <a class="header-anchor" href="#¿que-no-hace" aria-label="Permalink to &quot;¿Qué NO hace?&quot;">​</a></h2><ul><li>No tiene categorías de productos — todos aparecen en un grid plano</li><li>No tiene búsqueda ni filtros (por precio, categoría, etc.)</li><li>No maneja inventario ni stock automático</li><li>No tiene reseñas ni valoraciones de clientes</li><li>No permite comparar productos</li></ul><h2 id="disponibilidad-por-plan" tabindex="-1">Disponibilidad por plan <a class="header-anchor" href="#disponibilidad-por-plan" aria-label="Permalink to &quot;Disponibilidad por plan&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Característica</th><th>Básico (REF 9/mes)</th><th>Semestral (REF 39)</th><th>Anual (REF 69/año)</th></tr></thead><tbody><tr><td>Máximo de productos</td><td>20</td><td>100</td><td>Ilimitados</td></tr><tr><td>Imágenes por producto</td><td>1</td><td>3</td><td>6</td></tr><tr><td>Variantes</td><td>Solo simple</td><td>Talla + talla/color</td><td>Todas + opciones</td></tr><tr><td>Badges</td><td>✅</td><td>✅</td><td>✅</td></tr></tbody></table><h2 id="ejemplo-practico" tabindex="-1">Ejemplo práctico <a class="header-anchor" href="#ejemplo-practico" aria-label="Permalink to &quot;Ejemplo práctico&quot;">​</a></h2><h3 id="caso-proveedor-distribuve-en-valencia" tabindex="-1">Caso: Proveedor &quot;DistribuVE&quot; en Valencia <a class="header-anchor" href="#caso-proveedor-distribuve-en-valencia" aria-label="Permalink to &quot;Caso: Proveedor &quot;DistribuVE&quot; en Valencia&quot;">​</a></h3><p>Carlos es proveedor mayorista con plan Anual. Sube:</p><ol><li>&quot;Detergente industrial 5L&quot; → REF 12 → badge 🔥 Hot → 3 fotos</li><li>&quot;Cloro al 10% galón&quot; → REF 8 → opciones: &quot;Cantidad: 1 galón / Caja 6 galones (+REF 40)&quot;</li><li>&quot;Kit limpieza oficina&quot; → REF 25 → badge 🆕 Nuevo</li></ol><p>Su catálogo profesional le permite compartir el link a sus clientes por WhatsApp en lugar de mandar fotos una por una.</p>',24)),i(a,null,{default:l(()=>[...t[0]||(t[0]=[s(" Agregar buenas fotos a tus productos aumenta significativamente las consultas. Un producto sin foto recibe mucho menos atención que uno con foto. ",-1)])]),_:1}),t[2]||(t[2]=o('<h2 id="ver-tambien" tabindex="-1">Ver también <a class="header-anchor" href="#ver-tambien" aria-label="Permalink to &quot;Ver también&quot;">​</a></h2><ul><li><a href="/cat/badges-productos.html">Badges en productos</a> — Cómo usar 🆕 Nuevo, 🔥 Hot, 💰 Promo</li><li><a href="/cat/variantes.html">Variantes de productos</a> — Tallas, colores y opciones</li><li><a href="/cat/carrito-whatsapp.html">Carrito y WhatsApp</a> — Cómo funciona el checkout</li></ul>',2))])}const v=e(c,[["render",u]]);export{f as __pageData,v as default};
